class Solution:
    def baseNeg2(self, n: int) -> str:
        if n == 0:
            return "0"
        result = []
        while n != 0:
            remainder = n % -2
            if remainder >= 0:
                result.append("1")
                n = n // -2 - 1
            else:
                result.append("0")
                n = n // -2
        return "".join(result[::-1])
```
